def sum(a, b):
    return a + b

def _test():
    test_cases = [
        (0, 0),
        (1, 2),
        (-1, 5),
        (100, -50),
        (-10, -20),
        (2**31-1, -(2**31)),
    ]
    for a, b in test_cases:
        result = sum(a, b)
        expected = a + b
        if result != expected:
            print(f'CRITERIO FALLO: sum({a}, {b}) returned {result} expected {expected}')
            return
    print('CRITERIO OK')

if __name__ == '__main__':
    _test()

